            ContentJson = """{"appRoute":"/admin","startButtonLabel":"Tour Admin Panel","steps":[{"element":".admin-content","popover":{"title":"Where Admin Settings Live","description":"The Admin panel groups your settings into tabs along the sidebar. This area shows whatever tab you have open — users, track types, settings, integrations, compliance, training, or reference data.","side":"top"}},{"element":"app-page-header","popover":{"title":"Section Header","description":"The header names the section you're in and holds its action buttons. Use the main button to add something new — a user, a track type, and so on — to the tab you're viewing.","side":"bottom"}},{"element":"[data-testid='overview-card-people']","popover":{"title":"People Card","description":"This card sums up your user accounts: how many are active and a breakdown by role. It's one of several summary cards on the overview. Click its button to open the full Users screen, where you can sort and filter everyone.","side":"top"}},{"element":".admin-overview-card__header","popover":{"title":"Card Title","description":"Each summary card has an icon and a title — People, Capabilities, Connections, Compliance, and more. The title tells you at a glance which part of the Admin panel that card covers.","side":"bottom"}},{"element":"[data-testid='overview-card-people-go']","popover":{"title":"Open a Section","description":"Each card's button jumps straight to its Admin section — this one opens Users. Click any card's button to leave the overview and manage that area directly.","side":"left"}}]}"""
