            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/admin"]""",
            Tags = """["admin","reference"]""",
            ContentJson = """{"title":"Admin Field Reference","groups":[{"heading":"User Form Fields","items":[{"label":"First Name (required)","value":"Type the person's first name. Up to 100 characters; you can't save without it."},{"label":"Last Name (required)","value":"Type the person's last name. Up to 100 characters; you can't save without it."},{"label":"Email (required, create only)","value":"Type a valid email address, up to 256 characters. This is hidden when editing — an email can't be changed later."},{"label":"Initials (optional)","value":"Up to 3 characters shown on the person's avatar. Left blank, they're built from the name automatically."},{"label":"Role (required)","value":"Pick the person's role — Engineer, Production Worker, PM, Manager, Office Manager, or Admin. The role sets what they can do."},{"label":"Work Location (optional)","value":"Pick which location the person works at. Appears only when you have more than one location, and it sets their state withholding forms."},{"label":"Avatar Color","value":"Click one of the ten color swatches to set the background color of the person's avatar."},{"label":"Is Active (edit only)","value":"An on/off switch. Turning it off stops the person logging in but keeps all their past records."},{"label":"Scan Identifiers (edit only)","value":"The badge or tag IDs used at kiosks. Pick a type, type the value, and click Add; remove any of them one at a time."}]},{"heading":"User Actions","items":[{"label":"Add User button","value":"Opens the new-user form. You never set a password — the system creates a setup link the person uses instead."},{"label":"Get Setup Code","value":"Creates the secure setup link the person follows to finish setting up their account. Shows for anyone who hasn't set a password yet."},{"label":"Copy Setup Code","value":"Copies the setup link so you can paste it into an email or message for the person."},{"label":"Edit User (pencil icon)","value":"Opens the edit form filled in with the person's current details."},{"label":"Toggle Active (person icon)","value":"Turns the person's account off or back on."},{"label":"Badge reader status","value":"Shows whether a badge reader is connected at this computer, with a button to download the helper that lets it register scans."}]},{"heading":"Track Type Dialog Fields","items":[{"label":"Name (required)","value":"The name shown for this board type, such as Production or R&D/Tooling."},{"label":"Code (required)","value":"A short identifier in capital letters, numbers, and underscores (like PRODUCTION). It's fixed once saved."},{"label":"Description (optional)","value":"A short note on when this board type is used."},{"label":"Stage Name","value":"The name shown for each stage, such as In Production or QC/Review."},{"label":"Stage Code","value":"A short identifier for each stage. It's fixed once saved."},{"label":"Stage Color","value":"Pick the color for each stage's column heading on the board."},{"label":"WIP Limit","value":"The most jobs allowed in a stage at once. Go over it and the column heading turns red. Leave it 0 or blank for no limit."},{"label":"Irreversible checkbox","value":"When checked, jobs can't move back past this stage. Used for stages that create accounting documents, like Invoice or Payment."},{"label":"Move Up/Down buttons","value":"Reorder the stages. Grayed out when a stage is already at the top or bottom."},{"label":"Add Stage button","value":"Adds a new blank stage to the list."},{"label":"Delete Stage button","value":"Removes a stage. You must keep at least one."}]},{"heading":"Company Profile Fields","items":[{"label":"Company Name","value":"Shown on invoices, packing slips, and other documents customers see."},{"label":"Phone","value":"The company phone number, formatted as (XXX) XXX-XXXX."},{"label":"Email","value":"The company's main contact email address."},{"label":"EIN","value":"Your Employer Identification Number, in the form XX-XXXXXXX."},{"label":"Website","value":"Your company website address, starting with https://."}]},{"heading":"Company Location Fields","items":[{"label":"Name (required)","value":"The location's name, such as Main Office or Warehouse B. Up to 100 characters."},{"label":"Phone","value":"The location's phone number."},{"label":"Address","value":"The full address — street, city, state, and ZIP."},{"label":"Is Active (edit only)","value":"An on/off switch. Inactive locations no longer show up when assigning people to a location."},{"label":"Set as Default button","value":"Makes this the company's default location. Only one can be the default."}]},{"heading":"Events Dialog Fields","items":[{"label":"Title (required)","value":"The event name, up to 200 characters."},{"label":"Event Type (required)","value":"Pick the kind of event: Meeting, Training, Safety, or Other."},{"label":"Location","value":"Where the event is held. Optional."},{"label":"Start Date (required)","value":"Pick the day the event starts."},{"label":"Start Time (required)","value":"The start time, entered as HH:MM."},{"label":"End Date (required)","value":"Pick the day the event ends."},{"label":"End Time (required)","value":"The end time, entered as HH:MM."},{"label":"Description","value":"Extra details about the event. Optional."},{"label":"Attendees","value":"Pick the people invited to the event."},{"label":"Required","value":"An on/off switch. When on, attendees get a mandatory notice they must attend."},{"label":"Save button","value":"Saves the event. Grayed out until the form is complete or while it's saving."}]},{"heading":"AI Assistant Dialog Fields","items":[{"label":"Name (required)","value":"The assistant's name, shown on its sidebar card. Up to 100 characters."},{"label":"Description","value":"A short line under the name, shown on the card and welcome screen. Up to 500 characters."},{"label":"Category (required)","value":"Pick a category: General, HR, Procurement, Sales, or Custom."},{"label":"Icon (required)","value":"The icon shown for the assistant. Pick from the icon names available."},{"label":"Color (required)","value":"Pick the background color behind the assistant's icon."},{"label":"System Prompt (required)","value":"The instructions that tell the assistant how to behave and respond."},{"label":"Allowed Entity Types","value":"Pick which kinds of records the assistant is allowed to search across."},{"label":"Starter Questions","value":"Suggested questions shown to get a conversation going. Add or remove them freely."},{"label":"Answer style (advanced)","value":"A slider from predictable to creative (default in the middle). Lower keeps answers consistent and on-script; higher lets the assistant vary its wording more."},{"label":"Background depth (advanced)","value":"How much of your company's reference material the assistant pulls in per answer (default a handful of sources). More gives fuller answers; fewer keeps it tightly on point."}]},{"heading":"EDI Trading Partner Fields","items":[{"label":"Name (required)","value":"The trading partner's name, up to 200 characters."},{"label":"Qualifier ID (required)","value":"The partner's qualifier code, up to 10 characters. Defaults to ZZ."},{"label":"Qualifier Value (required)","value":"The partner's identifier value, up to 100 characters."},{"label":"Default Format","value":"Pick the message format: X12 or EDIFACT."},{"label":"Transport Method","value":"Pick how messages are exchanged: AS2, SFTP, VAN, Email, API, or Manual."},{"label":"Auto Process","value":"An on/off switch, on by default. Handles incoming messages automatically."},{"label":"Require Acknowledgment","value":"An on/off switch, on by default. Requires a receipt confirmation for each message."},{"label":"Notes","value":"Any extra notes about this partner. Optional."}]},{"heading":"Audit Log Filters","items":[{"label":"Entity Type","value":"Narrow the log to one kind of record — jobs, parts, customers, vendors, invoices, payments, and so on."},{"label":"Action","value":"Filter by what happened, such as Create, Update, or Delete."},{"label":"From Date","value":"Pick the start of the date range to show."},{"label":"To Date","value":"Pick the end of the date range to show."},{"label":"Pagination","value":"Choose how many rows per page — 25, 50, or 100. Starts at 25."}]},{"heading":"Sales Tax Rate Fields","items":[{"label":"Name (required)","value":"The name for this tax rate, up to 100 characters."},{"label":"Code (required)","value":"A short unique identifier for the rate, up to 20 characters."},{"label":"State Code","value":"Pick the US state this rate applies to."},{"label":"Rate Percent (required)","value":"The tax percentage, from 0 to 100."},{"label":"Effective From","value":"Pick the date this rate starts to apply."},{"label":"Description","value":"Any notes about this rate. Optional."},{"label":"Is Default","value":"An on/off switch. Makes this the default tax rate."}]}]}"""
